import { forwardRef } from "react";
import type { HTMLAttributes } from "react";
import { Slot } from "@radix-ui/react-slot";
import { clsx } from "clsx";
import * as styles from "./Tile.css";
import type { TileSize } from "./Tile.config";
import { DEFAULT_TILE_SIZE } from "./Tile.config";

export interface TileCustomProps {
  /**
   * The size of the tile, which controls the padding.
   * @default 'sm'
   */
  size?: TileSize;

  /**
   * Whether the tile is disabled.
   * @default false
   */
  disabled?: boolean;

  /**
   * When true, the component will not render its own element.
   * Instead, it will clone the first child element and merge props onto it.
   * @default false
   */
  asChild?: boolean;
}

export interface TileProps
  extends
    Omit<HTMLAttributes<HTMLDivElement>, keyof TileCustomProps>,
    TileCustomProps {}

/**
 * A style-only tile component for displaying content in a bordered container.
 *
 * **How it works:** By default, Tile renders a `<div>` element with tile styling.
 * When `asChild` is true, it merges the tile styles onto the first child element
 * instead, allowing you to use Tile with interactive elements like `<button>` or `<a>`.
 *
 * @example
 * <Tile size="md">
 *   <Icon>...</Icon>
 * </Tile>
 *
 * @example
 * <Tile asChild>
 *   <button type="button">Click me</button>
 * </Tile>
 */
export const Tile = forwardRef<HTMLDivElement, TileProps>(
  (
    {
      size = DEFAULT_TILE_SIZE,
      disabled = false,
      asChild = false,
      className,
      children,
      ...props
    },
    ref
  ) => {
    const tileClasses = clsx(styles.tile({ size }), className);

    const elementProps = {
      ...props,
      ref,
      className: tileClasses,
      "aria-disabled": disabled || undefined,
    };

    const Component = asChild ? Slot : "div";

    return <Component {...elementProps}>{children}</Component>;
  }
);

Tile.displayName = "Tile";
